code = """# Load the results from previous queries
businesses_with_parking = var_functions.query_db:5
businesses_reviewed_2018 = var_functions.query_db:2

# Extract the numeric IDs from business_id (format: businessid_X) and business_ref (format: businessref_X)
parking_ids = set()
for doc in businesses_with_parking:
    business_id = doc.get('business_id', '')
    if business_id.startswith('businessid_'):
        numeric_id = business_id.replace('businessid_', '')
        parking_ids.add(numeric_id)

# Extract numeric IDs from businesses that received reviews in 2018
reviewed_ids = set()
for row in businesses_reviewed_2018:
    business_ref = row.get('business_ref', '')
    if business_ref.startswith('businessref_'):
        numeric_id = business_ref.replace('businessref_', '')
        reviewed_ids.add(numeric_id)

# Find intersection - businesses reviewed in 2018 AND have parking attributes
common_businesses = parking_ids.intersection(reviewed_ids)

# Count the result
count = len(common_businesses)
import json
result = {"count": count}
print('__RESULT__:')
print(json.dumps(result))"""

